query:
-- Primeiro verificar os complementos existentes
SELECT mao.id, mao.name, mao.priceExtra, mag.name as group_name 
FROM menu_addon_options mao 
JOIN menu_addon_groups mag ON mao.groupId = mag.id 
WHERE mag.name LIKE '%Turbine%' OR mag.name LIKE '%turbine%'
ORDER BY mao.name;

-- Atualizar preços conforme tabela fornecida
